const data = $input.first().json.data;

const campos = ['codigo_IB', 'codigo_TH', 'codigo_salinas'];

const temCodigoPreenchido = data.some(item =>
  campos.some(campo => {
    const val = item[campo];
    return val !== null && val !== undefined && String(val).trim() !== '';
  })
);

return [{
  json: {
    temCodigo: temCodigoPreenchido
  }
}];

